&-option {
  display: flex;
  flex: 0 0 @size-6;
  flex: 0 0 var(--am-stepper-btn-size, @size-6);
  height: @size-6;
  height: var(--am-stepper-btn-size, @size-6);
  justify-content: center;
  align-items: center;
  border: @border-width-standard solid @color-divider-line;
  border: var(--am-stepper-borderWidth, @border-width-standard) solid var(--am-stepper-borderColor, @color-divider-line);
  border-radius: @corner-radius-sm;
  border-radius: var(--am-stepper-borderRadius, @corner-radius-sm);
  box-sizing: border-box;
}

&-clear {
  display: flex;
  align-items: center;
  position: relative;
  visibility: hidden;
  width: @size-7;
  width: var(--am-search-icon-area, @size-7);
  height: @size-7;
  height: var(--am-search-icon-area, @size-7);
  &-font {
    font-size: @font-size-subtitle;
    font-size: var(--am-search-iconsize, @font-size-subtitle);
    color: @color-text-weak;
    color: var(--am-search-clearicon-color, @color-text-weak);
  }
}

&-voice {
  display: flex;
  align-items: center;
  position: relative;
  width: @size-7;
  width: var(--am-search-icon-area, @size-7);
  height: @size-7;
  height: var(--am-search-icon-area, @size-7);
  &-font {
    font-size: @font-size-subtitle;
    font-size: var(--am-search-iconsize, @font-size-subtitle);
    color: @color-text-subtitle;
    color: var(--am-search-vocieicon-color, @color-text-subtitle);
  }
}

&-title {
  margin: @size-5 auto 0;
  margin: var(--am-result-margin-vertical, @size-5) auto 0;
  max-width: calc(100vw - @size-12);
  max-width: calc(100vw - var(--am-result-title-h-spacing, @size-12));
  overflow: hidden;
  text-overflow: ellipsis;
  white-space: nowrap;
  text-align: center;
  font-size: @font-size-title;
  font-size: var(--am-result-title-fontSize, @font-size-title);
  color: @color-text-title;
  color: var(--am-result-title-color, @color-text-title);
}

&-option {
  flex: 1;
  text-align: right;
  align-self: center;
  &__arrow {
    margin-left: @size-1/2;
    margin-top: @size-1;
    vertical-align: -@size-1/2;
    font-size: @font-size-subtitle;
    font-size: var(--am-coupon-detail-arrow-size, @font-size-subtitle);
    color: @color-text-weak;
    color: var(--am-coupon-detail-arrow-color, @color-text-weak);
  }
}

&-handle {
  display: flex;
  justify-content: center;
  align-items: center;
  width: calc(var(--height) - 2 * var(--border-width));
  height: calc(var(--height) - 2 * var(--border-width));
  border-radius: calc(var(--height) - 2 * var(--border-width));
  background: var(--adm-color-text-light-solid);
  position: absolute;
  z-index: 2;
  top: var(--border-width);
  left: var(--border-width);
  transition: all 200ms;
  box-shadow: 0 0 2px 0 rgba(0, 0, 0, 0.2), 0 2px 11.5px 0 rgba(0, 0, 0, 0.08),
    -1px 2px 2px 0 rgba(0, 0, 0, 0.1);
}

h1, .h1,
