@supports (backdrop-filter: blur(1px)) or (-webkit-backdrop-filter: blur(1px)) {
    .v-backdrop-blurs {
        -webkit-backdrop-filter: blur(10px);
        backdrop-filter: blur(10px);
    }

    #write .v-post-card.v-backdrop-blurs {
        background: var(--pn08);
    }

    .v-caption.full.v-backdrop-blurs {
        background: radial-gradient(rgba(var(--df-r-lg), var(--df-g-lg), var(--df-b-lg),1) 50%,
            rgba(var(--df-r-lg), var(--df-g-lg), var(--df-b-lg),.9));
    }
}

@keyframes stroke-dash-loop {
  0% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-0, 1, 200);
    stroke-dashoffset: var(--tv-motion-stroke-offset-0, 0);
  }
  50% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-50, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-50, -40px);
  }
  100% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-100, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-100, -120px);
  }
}

@keyframes stroke-dash-reverse {
  0% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-0, 1, 200);
    stroke-dashoffset: var(--tv-motion-stroke-offset-0, 0);
  }
  50% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-50, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-reverse-50, 40px);
  }
  100% {
    stroke-dasharray: var(--tv-motion-stroke-dasharray-100, 90, 150);
    stroke-dashoffset: var(--tv-motion-stroke-offset-reverse-100, 120px);
  }
}

@keyframes enlarge-in-fade {
  0% {
    transform: scale(var(--tv-motion-scale-start, 0));
    opacity: var(--tv-motion-scale-opacity-start, 0);
  }
  50% {
    transform: scale(var(--tv-motion-scale-mid, 0.5));
    opacity: var(--tv-motion-scale-opacity-mid, 0.5);
  }
  100% {
    transform: scale(var(--tv-motion-scale-end, 1));
    opacity: var(--tv-motion-scale-opacity-end, 1);
  }
}

@keyframes shrink-out-fade {
  0% {
    transform: scale(var(--tv-motion-scale-end, 1));
    opacity: var(--tv-motion-scale-opacity-end, 1);
  }
  50% {
    transform: scale(var(--tv-motion-scale-mid, 0.5));
    opacity: var(--tv-motion-scale-opacity-mid, 0.5);
  }
  100% {
    transform: scale(var(--tv-motion-scale-start, 0));
    opacity: var(--tv-motion-scale-opacity-start, 0);
  }
}

&--out {
  flex-direction: row-reverse;

  .AvocadoMessages-skeleton-line {
    background: linear-gradient(
      90deg,
      color-mix(in srgb, var(--primary-color) 25%, var(--avmsg-sk-base)) 25%,
      color-mix(in srgb, var(--primary-color) 15%, var(--avmsg-sk-shine)) 50%,
      color-mix(in srgb, var(--primary-color) 25%, var(--avmsg-sk-base)) 75%
    );
    background-size: 800px 100%;
    animation: avmsg-shimmer 1.4s infinite linear;
  }
}

