&::after {
  content: "";
  background-color: var(--weui-BG-2);
  width: ~"calc(var(--weui-STEPS-DOT-SIZE) +  2 * var(--weui-STEPS-HORIZONAL-DOT-GAP))";
  height: ~"calc(var(--weui-STEPS-DOT-SIZE) +  2 * var(--weui-STEPS-HORIZONAL-DOT-GAP))";
  position: absolute;
  top: 0;
  left: 0;
  transform: translate(~"calc(-50% + var(--weui-STEPS-DOT-SIZE) / 2)", -50%);
}

&.is-visible .primary-nav__item {
	.transition( all 240ms cubic-bezier(0.645, 0.045, 0.355, 1) );
	.translate3d(0, 0, 0);
	opacity: 1;

	&:nth-child(1) { .transition-delay(100ms); }
	&:nth-child(2) { .transition-delay(200ms); }
	&:nth-child(3) { .transition-delay(300ms); }
	&:nth-child(4) { .transition-delay(400ms); }
	&:nth-child(5) { .transition-delay(500ms); }
	&:nth-child(6) { .transition-delay(600ms); }
	&:nth-child(7) { .transition-delay(700ms); }
}

&__node {
  position: absolute;
  top: 2px;
  left: 2px;
  width: var(--van-switch-node-size);
  height: var(--van-switch-node-size);
  // https://github.com/vant-ui/vant/issues/9839
  font-size: inherit;
  background: var(--van-switch-node-background);
  border-radius: 100%;
  box-shadow: var(--van-switch-node-shadow);
  transition: transform var(--van-switch-duration)
    cubic-bezier(0.3, 1.05, 0.4, 1.05);
}

& .Search-input {
	& when (lightness(@header-bg) <= 50%) {
		--fluent-temp-input-text-color: ~"#ffffffc8";
		&:active, &:focus-within {
			--fluent-temp-input-text-color: white;
		}
	}
	& when (lightness(@header-bg) > 50%) {
		--fluent-temp-input-text-color: ~"#000000a8";
		&:active, &:focus-within {
			--fluent-temp-input-text-color: black;
		}
	}
}
